parameters.jsCode:
return items.map(item => {

  const p = item.json;

  return {
    json: {
      id: p.id,

      title: p.name || "Untitled",

      hook: p.property_hooks || "",

      tone: p.property_tone || "",

      audience: p.property_audience || "",

      selectedHook:
        p.property_selected_one_liner || "",

      script:
        p.property_speaking_script_final || "",

      marketingHooks:
        p.property_marketing_hooks
          ?.split(/\n\d+\.\s/)
          .filter(Boolean)
          .map(h => h.trim()) || [],

      keyframes:
        p.property_keyframe_prompts
          ?.split("• ")
          .filter(Boolean)
          .map(text => ({
            text: text.trim(),
            image: null
          })) || [],

      storyboard:
        p.property_storyboard_prompt || "",

      videoHook:
        p.property_video_prompt_hook_part || "",

      videoSpeak:
        p.property_video_prompt_speaking_part || ""
    }
  };
});
